// Parsear CSV del catálogo Arfagi
// Columnas: SKU;Producto;Marca;Categoria;Genero;Precio (Gs.);Stock;Disponible;Destacado;Nuevo;Descripcion

const csvText = $input.first().json.data;
const lines = csvText.split('\n').filter(l => l.trim());
const headers = lines[0].split(';').map(h => h.trim());

const productos = [];

for (let i = 1; i < lines.length; i++) {
  const cols = lines[i].split(';');
  if (cols.length < 8) continue;

  const sku = cols[0]?.trim();
  if (!sku) continue;

  // Normalizar precio: 'Gs. 320.000' → 320000 (entero, sin decimales)
  const precioRaw = cols[5]?.trim() || '0';
  const precioGs = parseInt(precioRaw.replace(/[Gs\.\s]/g, '').replace(/\./g, '')) || 0;

  // Calcular rango de precio para RAG
  let rangoPrecio = 'ACCESIBLE';
  if (precioGs > 800000) rangoPrecio = 'LUJO';
  else if (precioGs > 500000) rangoPrecio = 'PREMIUM';
  else if (precioGs > 250000) rangoPrecio = 'MID';

  const stockTotal = parseInt(cols[6]?.trim()) || 0;
  const disponible = cols[7]?.trim()?.toLowerCase() === 'si';
  const destacado = cols[8]?.trim()?.toLowerCase() === 'si';
  const nuevo = cols[9]?.trim()?.toLowerCase() === 'si';

  // Generar tags RAG automáticos para búsqueda semántica
  const nombre = cols[1]?.trim() || '';
  const marca = cols[2]?.trim() || '';
  const categoria = cols[3]?.trim() || 'Perfume';
  const genero = cols[4]?.trim() || 'Unisex';
  const descripcion = cols[10]?.trim() || '';

  const tagsRag = [
    marca.toLowerCase(),
    genero.toLowerCase(),
    categoria.toLowerCase(),
    rangoPrecio.toLowerCase()
  ].filter(Boolean);

  productos.push({
    json: {
      sku,
      nombre,
      descripcion,
      marca: marca.toUpperCase(),
      categoria,
      genero,
      precio_gs: precioGs,
      rango_precio: rangoPrecio,
      stock_total: stockTotal,
      stock_disponible: stockTotal, // Al importar, stock_bloqueado = 0
      stock_bloqueado: 0,
      disponible,
      destacado,
      nuevo,
      imagen_url: '',
      embedding_ref: '',
      tags_rag: tagsRag
    }
  });
}

console.log(`Parseados ${productos.length} productos del CSV`);
return productos;

const items = $input.all();
const exitosos = items.filter(i => i.json.exito !== false).length;
const errores = items.filter(i => i.json.exito === false).length;

console.log(`=== SYNC CATÁLOGO ARFAGI ===`);
console.log(`✅ Sincronizados: ${exitosos}`);
console.log(`❌ Errores: ${errores}`);
console.log(`📦 Total procesados: ${items.length}`);

return [{
  json: {
    sync_completado: true,
    total_procesados: items.length,
    exitosos,
    errores,
    timestamp: new Date().toISOString()
  }
}];
